mapper.sql:
from aiw_scheduled_task_execution e
where 1 = 1

    and e.task_code = #{criteria.taskCode}


    and e.task_type = #{criteria.taskType}


    and e.status = #{criteria.status}


    and e.started_at >= #{criteria.startedFrom}


    and e.started_at <= #{criteria.startedTo}

mapper.select:
select e.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
